CREATE EXTENSION IF NOT EXISTS "pgcrypto";
CREATE TABLE IF NOT EXISTS users (id UUID PRIMARY KEY DEFAULT gen_random_uuid(), email VARCHAR(255) UNIQUE NOT NULL, password_hash VARCHAR(255) NOT NULL, full_name VARCHAR(100) NOT NULL, university VARCHAR(150), major VARCHAR(100), year_of_study SMALLINT, gpa NUMERIC(3,2), role VARCHAR(20) DEFAULT 'student', is_active BOOLEAN DEFAULT TRUE, is_verified BOOLEAN DEFAULT FALSE, last_seen TIMESTAMPTZ, created_at TIMESTAMPTZ DEFAULT NOW(), updated_at TIMESTAMPTZ DEFAULT NOW());
CREATE TABLE IF NOT EXISTS profiles (id UUID PRIMARY KEY DEFAULT gen_random_uuid(), user_id UUID UNIQUE NOT NULL REFERENCES users(id) ON DELETE CASCADE, avatar_url VARCHAR(500), bio TEXT, learning_style VARCHAR(30), academic_goal VARCHAR(50), availability VARCHAR(20) DEFAULT 'flexible', xp_points INTEGER DEFAULT 0, streak_days INTEGER DEFAULT 0, is_public BOOLEAN DEFAULT TRUE, created_at TIMESTAMPTZ DEFAULT NOW(), updated_at TIMESTAMPTZ DEFAULT NOW());
CREATE TABLE IF NOT EXISTS subjects (id UUID PRIMARY KEY DEFAULT gen_random_uuid(), name VARCHAR(100) UNIQUE NOT NULL, category VARCHAR(50), code VARCHAR(20) UNIQUE);
CREATE TABLE IF NOT EXISTS user_subjects (user_id UUID NOT NULL REFERENCES users(id) ON DELETE CASCADE, subject_id UUID NOT NULL REFERENCES subjects(id) ON DELETE CASCADE, skill_level VARCHAR(20) DEFAULT 'intermediate', is_seeking BOOLEAN DEFAULT TRUE, PRIMARY KEY(user_id, subject_id));
CREATE TABLE IF NOT EXISTS schedules (id UUID PRIMARY KEY DEFAULT gen_random_uuid(), user_id UUID NOT NULL REFERENCES users(id) ON DELETE CASCADE, day_of_week SMALLINT NOT NULL, time_slot VARCHAR(10) NOT NULL, UNIQUE(user_id,day_of_week,time_slot));
CREATE TABLE IF NOT EXISTS matches (id UUID PRIMARY KEY DEFAULT gen_random_uuid(), user_id_a UUID NOT NULL REFERENCES users(id) ON DELETE CASCADE, user_id_b UUID NOT NULL REFERENCES users(id) ON DELETE CASCADE, score NUMERIC(5,2) NOT NULL, subject_score NUMERIC(5,2), schedule_score NUMERIC(5,2), style_score NUMERIC(5,2), goal_score NUMERIC(5,2), gpa_score NUMERIC(5,2), status VARCHAR(20) DEFAULT 'suggested', initiated_by UUID REFERENCES users(id), created_at TIMESTAMPTZ DEFAULT NOW(), updated_at TIMESTAMPTZ DEFAULT NOW(), CONSTRAINT ck_match_no_self CHECK(user_id_a<>user_id_b));
CREATE TABLE IF NOT EXISTS study_groups (id UUID PRIMARY KEY DEFAULT gen_random_uuid(), name VARCHAR(100) NOT NULL, description TEXT, icon VARCHAR(10), subject_id UUID REFERENCES subjects(id), owner_id UUID NOT NULL REFERENCES users(id), max_members SMALLINT DEFAULT 10, next_session TIMESTAMPTZ, is_public BOOLEAN DEFAULT TRUE, created_at TIMESTAMPTZ DEFAULT NOW());
CREATE TABLE IF NOT EXISTS group_members (group_id UUID NOT NULL REFERENCES study_groups(id) ON DELETE CASCADE, user_id UUID NOT NULL REFERENCES users(id) ON DELETE CASCADE, role VARCHAR(20) DEFAULT 'member', joined_at TIMESTAMPTZ DEFAULT NOW(), PRIMARY KEY(group_id,user_id));
CREATE TABLE IF NOT EXISTS conversations (id UUID PRIMARY KEY DEFAULT gen_random_uuid(), user_id_a UUID NOT NULL REFERENCES users(id), user_id_b UUID NOT NULL REFERENCES users(id), created_at TIMESTAMPTZ DEFAULT NOW(), updated_at TIMESTAMPTZ DEFAULT NOW(), UNIQUE(user_id_a,user_id_b));
CREATE TABLE IF NOT EXISTS messages (id UUID PRIMARY KEY DEFAULT gen_random_uuid(), conversation_id UUID NOT NULL REFERENCES conversations(id) ON DELETE CASCADE, sender_id UUID NOT NULL REFERENCES users(id), content TEXT NOT NULL, message_type VARCHAR(20) DEFAULT 'text', is_read BOOLEAN DEFAULT FALSE, created_at TIMESTAMPTZ DEFAULT NOW());
CREATE TABLE IF NOT EXISTS notifications (id UUID PRIMARY KEY DEFAULT gen_random_uuid(), user_id UUID NOT NULL REFERENCES users(id) ON DELETE CASCADE, type VARCHAR(40) NOT NULL, title VARCHAR(200) NOT NULL, body TEXT, data JSONB, is_read BOOLEAN DEFAULT FALSE, created_at TIMESTAMPTZ DEFAULT NOW());
CREATE TABLE IF NOT EXISTS feedback (id UUID PRIMARY KEY DEFAULT gen_random_uuid(), reviewer_id UUID NOT NULL REFERENCES users(id), reviewee_id UUID NOT NULL REFERENCES users(id), match_id UUID REFERENCES matches(id), rating SMALLINT, comment TEXT, created_at TIMESTAMPTZ DEFAULT NOW());
